package harness

import (
	"pgregory.net/rapid"

	"goforge.dev/rune/v3/surface"
)

// Well-typed term generation, for the Phase-1 properties. Terms are generated BY
// CONSTRUCTION against a target type drawn from the simple fragment
//
//	τ ::= U | τ -> τ
//
// (every τ is also a term of type U, since U : U until the Phase-6 hierarchy).
// This is deliberately a fragment: it cannot produce ill-typed terms, so the
// dual obligation — ill-typed terms are rejected — is covered by example tests
// in elaborate. The generator's job is breadth for the preservation/conversion
// properties, not full dependent-type coverage.

// Ty is the generator's view of a simple type.
type Ty interface{ isTy() }

// TyU is the universe.
type TyU struct{}

// TyArrow is a function type.
type TyArrow struct{ Dom, Cod Ty }

func (TyU) isTy()     {}
func (TyArrow) isTy() {}

// TyExp renders a generator type as a surface expression. TyU is U1: with the
// predicative hierarchy, the only closed inhabitants of a base universe are
// type EXPRESSIONS, which live one level up — so generated "values" of TyU are
// U_0-level types (U itself, arrows over U), classified by U1.
func TyExp(ty Ty) surface.Exp {
	switch t := ty.(type) {
	case TyU:
		return surface.EUniv{Lvl: 1}
	case TyArrow:
		return surface.EPi{Param: "_", Dom: TyExp(t.Dom), Cod: TyExp(t.Cod)}
	default:
		panic("unknown Ty")
	}
}

// GenTy draws a simple type with bounded depth.
func GenTy(t *rapid.T) Ty { return genTy(t, 2) }

func genTy(t *rapid.T, fuel int) Ty {
	if fuel <= 0 || rapid.IntRange(0, 2).Draw(t, "ty") == 0 {
		return TyU{}
	}
	return TyArrow{Dom: genTy(t, fuel-1), Cod: genTy(t, fuel-1)}
}

// typedScope is one in-scope binder with its generator type.
type typedScope struct {
	name string
	ty   Ty
}

// GenTypedExp draws a closed surface expression of the returned type. Every
// expression it produces elaborates and checks against TyExp(type) by
// construction.
func GenTypedExp(t *rapid.T) (surface.Exp, Ty) {
	ty := GenTy(t)
	return genTyped(t, nil, ty, 3), ty
}

func genTyped(t *rapid.T, scope []typedScope, want Ty, fuel int) surface.Exp {
	// A variable of the wanted type, when one is in scope and the dice agree.
	if v, ok := pickTypedVar(t, scope, want); ok && fuel >= 0 && rapid.Bool().Draw(t, "use-var") {
		return v
	}
	if fuel <= 0 {
		return atomOf(t, scope, want)
	}
	switch w := want.(type) {
	case TyArrow:
		switch rapid.IntRange(0, 2).Draw(t, "arrow-form") {
		case 0: // an application yielding an arrow is rare; prefer the lambda
			fallthrough
		case 1:
			n := freshName(scope)
			inner := append(append([]typedScope{}, scope...), typedScope{name: n, ty: w.Dom})
			return surface.ELam{Param: n, Dom: TyExp(w.Dom), Body: genTyped(t, inner, w.Cod, fuel-1)}
		default: // let-bind a value, then produce the arrow under it
			n := freshName(scope)
			bty := genTy(t, 1)
			inner := append(append([]typedScope{}, scope...), typedScope{name: n, ty: bty})
			return surface.ELet{
				Name: n,
				Val:  genTyped(t, scope, bty, fuel-1),
				Body: genTyped(t, inner, want, fuel-1),
			}
		}
	case TyU:
		switch rapid.IntRange(0, 3).Draw(t, "u-form") {
		case 0:
			return surface.EUniv{}
		case 1: // an arrow over U_0 is a term of type U1
			return surface.EPi{Param: "_", Dom: surface.EUniv{}, Cod: surface.EUniv{}}
		case 2: // β-redex of type U: (fn (x : A) is body end : A -> U) arg
			a := genTy(t, 1)
			n := freshName(scope)
			inner := append(append([]typedScope{}, scope...), typedScope{name: n, ty: a})
			lam := surface.ELam{Param: n, Dom: TyExp(a), Body: genTyped(t, inner, TyU{}, fuel-1)}
			return surface.EApp{Fn: lam, Arg: genTyped(t, scope, a, fuel-1)}
		default:
			return atomOf(t, scope, want)
		}
	}
	return atomOf(t, scope, want)
}

// atomOf produces a minimal inhabitant of want: U for TyU, an η-long constant
// lambda tower otherwise.
func atomOf(t *rapid.T, scope []typedScope, want Ty) surface.Exp {
	switch w := want.(type) {
	case TyU:
		if v, ok := pickTypedVar(t, scope, want); ok {
			return v
		}
		return surface.EUniv{}
	case TyArrow:
		n := freshName(scope)
		inner := append(append([]typedScope{}, scope...), typedScope{name: n, ty: w.Dom})
		return surface.ELam{Param: n, Dom: TyExp(w.Dom), Body: atomOf(t, inner, w.Cod)}
	default:
		panic("unknown Ty")
	}
}

func pickTypedVar(t *rapid.T, scope []typedScope, want Ty) (surface.Exp, bool) {
	var hits []string
	for _, b := range scope {
		if tyEqual(b.ty, want) {
			hits = append(hits, b.name)
		}
	}
	if len(hits) == 0 {
		return nil, false
	}
	return surface.EVar{Name: rapid.SampledFrom(hits).Draw(t, "typed-var")}, true
}

func tyEqual(a, b Ty) bool {
	switch x := a.(type) {
	case TyU:
		_, ok := b.(TyU)
		return ok
	case TyArrow:
		y, ok := b.(TyArrow)
		return ok && tyEqual(x.Dom, y.Dom) && tyEqual(x.Cod, y.Cod)
	default:
		return false
	}
}

func freshName(scope []typedScope) string {
	return "v" + itoa(len(scope)+1)
}
